# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
import os

class FileAccessControl:
    def __init__(self, db_name):
        self.conn = sqlite3.connect(db_name)
        self.cursor = self.conn.cursor()
        
        # Create table if not exists
        self.cursor.execute('''
            CREATE TABLE IF NOT EXISTS permissions (
                user_id INTEGER,
                file_path TEXT PRIMARY KEY,
                access_level INTEGER
            )
        ''')
        
        self.conn.commit()

    def check_permission(self, user_id, file_path):
        self.cursor.execute('SELECT access_level FROM permissions WHERE user_id=? AND file_path=?', (user_id, file_path))
        result = self.cursor.fetchone()
        if result:
            return True
        else:
            return False

    def get_file_contents(self, user_id, file_path):
        if self.check_permission(user_id, file_path):
            try:
                with open(file_path, 'r') as f:
                    contents = f.read()
                    return contents
            except FileNotFoundError:
                print(f"File {file_path} not found.")
                return None
        else:
            print(f"User {user_id} does not have permission to read file {file_path}.")
            return None

    def update_permission(self, user_id, file_path, access_level):
        self.cursor.execute('INSERT OR REPLACE INTO permissions (user_id, file_path, access_level) VALUES (?, ?, ?)', (user_id, file_path, access_level))
        self.conn.commit()

# Example usage
fa = FileAccessControl('permissions.db')
print(fa.get_file_contents(1, 'path/to/file.txt'))